import torch
import torch.nn as nn


class ConvEncoder(nn.Module):
    def __init__(self, in_channels: int = 1, z_dim: int = 64):
        super().__init__()
        # Each Conv2d halves the spatial size via stride=2
        self.net = nn.Sequential(
            nn.Conv2d(in_channels, 32, 4, stride=2, padding=1),   # H/2
            nn.ReLU(),
            nn.Conv2d(32, 64, 4, stride=2, padding=1),             # H/4
            nn.ReLU(),
            nn.Conv2d(64, 128, 4, stride=2, padding=1),            # H/8
            nn.ReLU(),
            nn.Flatten(),
        )
        # For 28x28 inputs (MNIST): 128 * 3 * 3 = 1152 features
        self.fc = nn.Linear(128 * 3 * 3, z_dim)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.fc(self.net(x))


class ConvDecoder(nn.Module):
    def __init__(self, z_dim: int = 64, out_channels: int = 1):
        super().__init__()
        self.fc = nn.Linear(z_dim, 128 * 3 * 3)
        # ConvTranspose2d doubles spatial size via stride=2
        self.net = nn.Sequential(
            nn.Unflatten(1, (128, 3, 3)),
            nn.ConvTranspose2d(128, 64, 4, stride=2, padding=1),   # 6x6
            nn.ReLU(),
            nn.ConvTranspose2d(64, 32, 4, stride=2, padding=1),    # 12x12
            nn.ReLU(),
            nn.ConvTranspose2d(32, out_channels, 4, stride=2, padding=1),  # 24x24
            nn.Sigmoid(),   # output in [0, 1] for normalised images
        )

    def forward(self, z: torch.Tensor) -> torch.Tensor:
        return self.net(self.fc(z))


class Autoencoder(nn.Module):
    def __init__(self, z_dim: int = 64):
        super().__init__()
        self.encoder = ConvEncoder(z_dim=z_dim)
        self.decoder = ConvDecoder(z_dim=z_dim)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        z = self.encoder(x)
        return self.decoder(z)

    def encode(self, x: torch.Tensor) -> torch.Tensor:
        return self.encoder(x)

    def decode(self, z: torch.Tensor) -> torch.Tensor:
        return self.decoder(z)

import torch
import torch.nn as nn


class DenoisingAutoencoder(Autoencoder):
    def __init__(self, z_dim: int = 64, noise_std: float = 0.1):
        super().__init__(z_dim=z_dim)
        self.noise_std = noise_std

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        if self.training:
            # Add Gaussian noise; clamp so the corrupted image stays in [0,1]
            noise = torch.randn_like(x) * self.noise_std
            x_corrupted = (x + noise).clamp(0.0, 1.0)
        else:
            x_corrupted = x    # no corruption at eval time

        z = self.encoder(x_corrupted)
        return self.decoder(z)


# Training loop is identical — compare x_hat against clean x, not x_corrupted
def train_dae(model, loader, epochs=20, lr=1e-3, device=torch.device('cpu')):
    model = model.to(device)
    optimiser = torch.optim.Adam(model.parameters(), lr=lr)
    loss_fn = nn.MSELoss()

    for epoch in range(epochs):
        for x, _ in loader:
            x = x.to(device)
            x_hat = model(x)       # model internally corrupts x during training
            loss = loss_fn(x_hat, x)   # target = clean x

            optimiser.zero_grad()
            loss.backward()
            optimiser.step()

import torch
import torch.nn as nn

class FCAutoencoder(nn.Module):
    def __init__(self, img_size: int = 28, latent_dim: int = 64):
        super().__init__()
        flat = img_size * img_size
        self.encoder = nn.Sequential(
            nn.Flatten(),
            nn.Linear(flat, 256), nn.ReLU(),
            nn.Linear(256, latent_dim),
        )
        self.decoder = nn.Sequential(
            nn.Linear(latent_dim, 256), nn.ReLU(),
            nn.Linear(256, flat), nn.Sigmoid(),
            nn.Unflatten(1, (1, img_size, img_size)),
        )

    def forward(self, x: torch.Tensor):
        return self.decoder(self.encoder(x))


def count_params(model: nn.Module) -> int:
    return sum(p.numel() for p in model.parameters())

# 28x28 grayscale -> latent_dim=64
# FC first-layer alone: 784 * 64 = 50,176 params per layer
# Conv encoder equivalent: far fewer params due to weight sharing
fc_ae = FCAutoencoder(img_size=28, latent_dim=64)
print(f"FC autoencoder total params: {count_params(fc_ae):,}")
